spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 12000;
    var progress = (t % duration) / duration;

    var gridW = 120;
    var gridH = 120;
    var startX = (W - gridW) / 2;
    var startY = H / 2 - 80;
    var boxSize = gridW / 10;

    // Stages
    // 0 - 2s: Empty grid
    // 2s - 4.5s: Shade 8 rows (0.8)
    // 4.5s - 7s: Shade 6 columns (0.6)
    // 7s - 9.5s: Highlight overlap (0.48)
    // 9.5s - 12s: Final math sentence

    var stage = 1;
    if (progress >= 0.16 && progress < 0.38) stage = 2;
    else if (progress >= 0.38 && progress < 0.58) stage = 3;
    else if (progress >= 0.58 && progress < 0.79) stage = 4;
    else if (progress >= 0.79) stage = 5;

    // Draw grid background
    ctx.fillStyle = '#1F2937';
    ctx.fillRect(startX, startY, gridW, gridH);

    // Shade rows (0.8 blue)
    var rowsShaded = 0;
    if (stage === 2) {
      rowsShaded = 8 * (progress - 0.16) / 0.22;
    } else if (stage >= 3) {
      rowsShaded = 8;
    }
    ctx.fillStyle = 'rgba(59, 130, 246, 0.45)';
    ctx.fillRect(startX, startY, gridW, rowsShaded * boxSize);

    // Shade columns (0.6 pink)
    var colsShaded = 0;
    if (stage === 3) {
      colsShaded = 6 * (progress - 0.38) / 0.20;
    } else if (stage >= 4) {
      colsShaded = 6;
    }
    ctx.fillStyle = 'rgba(236, 72, 153, 0.45)';
    ctx.fillRect(startX, startY, colsShaded * boxSize, gridH);

    // Highlight overlap (0.48 green)
    if (stage >= 4) {
      var overlapAlpha = (stage === 4) ? 0.7 * (progress - 0.58) / 0.21 : 0.7;
      ctx.fillStyle = 'rgba(16, 185, 129, ' + overlapAlpha + ')';
      ctx.fillRect(startX, startY, 6 * boxSize, 8 * boxSize);

      // Overlap border
      ctx.strokeStyle = '#34D399';
      ctx.lineWidth = 2;
      ctx.strokeRect(startX, startY, 6 * boxSize, 8 * boxSize);
    }

    // Grid lines
    ctx.strokeStyle = '#374151';
    ctx.lineWidth = 1;
    for (var i = 0; i <= 10; i++) {
      // Vertical lines
      ctx.beginPath();
      ctx.moveTo(startX + i * boxSize, startY);
      ctx.lineTo(startX + i * boxSize, startY + gridH);
      ctx.stroke();

      // Horizontal lines
      ctx.beginPath();
      ctx.moveTo(startX, startY + i * boxSize);
      ctx.lineTo(startX + gridW, startY + i * boxSize);
      ctx.stroke();
    }

    // Text labels & annotations
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.fillStyle = '#9CA3AF';
    ctx.font = '12px -apple-system, sans-serif';

    if (stage === 1) {
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('10 × 10 Area Grid (1 Whole)', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Each small square represents 0.01 (1 hundredth)', W / 2, H - 22);
    } else if (stage === 2) {
      ctx.fillStyle = '#60A5FA';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Shading 8 Tenths (0.8) Horizontally', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('8 rows shaded blue = 80 hundredths', W / 2, H - 22);
    } else if (stage === 3) {
      ctx.fillStyle = '#F472B6';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Shading 6 Tenths (0.6) Vertically', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('6 columns shaded pink = 60 hundredths', W / 2, H - 22);
    } else if (stage === 4) {
      ctx.fillStyle = '#34D399';
      ctx.font = 'bold 15px -apple-system, sans-serif';
      ctx.fillText('Identify the Overlapping Region', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('8 rows × 6 columns = 48 overlapping squares', W / 2, H - 22);
    } else {
      ctx.fillStyle = '#10B981';
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('0.8 × 0.6 = 0.48', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '11px -apple-system, sans-serif';
      ctx.fillText('Total overlap: 48 squares = 48 hundredths', W / 2, H - 22);
    }
  }
};
